#pragma GCC optimize("O3,unroll-loops")
#pragma GCC target("avx2,bmi,bmi2,lzcnt,popcnt")
#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& v) {
    int n = v.size(); if (n < 2) return;
    int *p = v.data(), i = 1;
    while (i < n && p[i] <= p[i-1]) ++i;
    if (p[0] > p[i-1]) std::reverse(p, p + i);
    while (i < n && p[i-1] <= p[i]) ++i;
    if (i == n) return;
    int mn = p[0], mx = mn;
    for (int x : v) mn = std::min(mn, x), mx = std::max(mx, x);
    long long r = (long long)mx - mn;
    if (r < 2000000 && r < n * 32LL) {
        std::vector<int> c(r + 1, 0);
        for (int x : v) c[x - mn]++;
        int* it = p;
        for (int j = 0; j <= r; ++j) if (int k = c[j]) it = std::fill_n(it, k, j + mn);
        return;
    }
    if (i * 4 > n || n - i < 80) {
        std::sort(p + i, p + n);
        if (p[i] < p[i-1]) std::inplace_merge(p, p + i, p + n);
    } else std::sort(p, p + n);
}

